 38→    /**
 39→     * 執行預設 — 查詢病假設定資料
 40→     * 業務規則 B3：僅回傳病假 1 筆（有效且日期在範圍內）
 41→     */
 42→    public List<Map<String, Object>> getDefaultVacation() {
 43→        String sql = """
 44→                SELECT A.VACATION_CODE, A.VACATION_NAME,
 45→                       B.VACATION_SUB_CODE, B.VACATION_SUB_NAME,
 46→                       B.VACATION_SUB_ID,
 47→                       B.MIN_HOURS, B.MAX_HOURS
 48→                  FROM EAP.TM_VACATION_SETTING A
 49→                  JOIN EAP.TM_VACATION_DETAIL_SETTING B
 50→                    ON A.VACATION_CODE = B.VACATION_CODE
 51→                 WHERE A.VACATION_NAME = NCHAR(30149) + NCHAR(20551)
 52→                   AND GETDATE() BETWEEN B.BEGIN_DATE
 53→                       AND ISNULL(B.END_DATE, CAST('2099-12-31' AS DATE))
 54→                   AND B.IS_EFFECTIVE = 1
 55→                """;
 56→
 57→        // 病 = U+75C5 = 30149, 假 = U+5047 = 20551
 58→        // Use NCHAR() to avoid encoding issues with Chinese characters
 59→        Query query = em.createNativeQuery(sql);
 60→        @SuppressWarnings("unchecked")
 61→        List<Object[]> rows = query.getResultList();
 62→
 63→        List<Map<String, Object>> result = new ArrayList<>();
 64→        for (Object[] row : rows) {
 65→            Map<String, Object> record = new HashMap<>();
 66→            record.put("vacationCode", row[0]);
 67→            record.put("vacationName", row[1]);
 68→            record.put("vacationSubCode", row[2]);
 69→            record.put("vacationSubName", row[3]);
 70→            record.put("vacationSubId", row[4]);
 71→            record.put("minHours", row[5]);
 72→            record.put("maxHours", row[6]);
 73→            result.add(record);
 74→        }
 75→        return result;
 76→    }
