 78→    /**
 79→     * 查詢員工假別明細
 80→     */
 81→    public List<Map<String, Object>> queryEmpVacationDetail(Integer empId, int year) {
 82→        String sql = """
 83→                SELECT
 84→                    v.EMP_VACATION_ID,
 85→                    v.EMP_ID,
 86→                    v.VACATION_SUB_ID,
 87→                    vds.VACATION_CODE,
 88→                    vs.VACATION_NAME,
 89→                    vds.VACATION_SUB_CODE,
 90→                    vds.VACATION_SUB_NAME,
 91→                    v.MAX_HOURS,
 92→                    v.USED_HOURS,
 93→                    v.UNUSED_HOURS,
 94→                    v.CASH_OUT_HOURS,
 95→                    v.BEGIN_DATE,
 96→                    v.END_DATE,
 97→                    v.CLEAR
 98→                FROM EAP.TM_EMP_VACATION v
 99→                INNER JOIN EAP.TM_VACATION_DETAIL_SETTING vds
100→                    ON vds.VACATION_SUB_ID = v.VACATION_SUB_ID
101→                INNER JOIN EAP.TM_VACATION_SETTING vs
102→                    ON vs.VACATION_CODE = vds.VACATION_CODE
103→                WHERE v.EMP_ID = :empId
104→                  AND YEAR(v.BEGIN_DATE) = :year
105→                ORDER BY v.VACATION_SUB_ID
106→                """;
107→
108→        Query query = em.createNativeQuery(sql);
109→        query.setParameter("empId", empId);
110→        query.setParameter("year", year);
111→
112→        @SuppressWarnings("unchecked")
113→        List<Object[]> rows = query.getResultList();
114→
115→        List<Map<String, Object>> result = new ArrayList<>();
116→        for (Object[] row : rows) {
117→            Map<String, Object> record = new HashMap<>();
118→            record.put("empVacationId", row[0]);
119→            record.put("empId", row[1]);
120→            record.put("vacationSubId", row[2]);
121→            record.put("vacationCode", row[3]);
122→            record.put("vacationName", row[4]);
123→            record.put("vacationSubCode", row[5]);
124→            record.put("vacationSubName", row[6]);
125→
126→            BigDecimal maxHours = toBigDecimal(row[7]);
127→            BigDecimal usedHours = toBigDecimal(row[8]);
128→            BigDecimal unusedHours = toBigDecimal(row[9]);
129→
130→            record.put("maxHours", maxHours);
131→            record.put("totalHours", maxHours);
132→            record.put("usedHours", usedHours);
133→            record.put("unusedHours", unusedHours);
134→            record.put("remainingHours", unusedHours);
135→            record.put("cashOutHours", row[10]);
136→            record.put("beginDate", formatDate(row[11]));
137→            record.put("endDate", formatDate(row[12]));
138→
139→            // CLEAR 欄位 — 結算狀態
140→            Object clearVal = row[13];
141→            boolean isClear = false;
142→            if (clearVal != null) {
143→                if (clearVal instanceof Boolean) {
144→                    isClear = (Boolean) clearVal;
145→                } else if (clearVal instanceof Number) {
146→                    isClear = ((Number) clearVal).intValue() == 1;
147→                }
148→            }
149→            record.put("clear", isClear);
150→            record.put("settlementStatus", isClear ? "Y" : "");
151→
152→            result.add(record);
153→        }
154→        return result;
155→    }
