157→    /**
158→     * 儲存員工假別明細（新增 + 修改）
159→     * 業務規則 B1：UNUSED_HOURS = MAX_HOURS - USED_HOURS
160→     * 業務規則 B5：不修改 CLEAR 欄位
161→     */
162→    @Transactional
163→    @SuppressWarnings("unchecked")
164→    public List<Map<String, Object>> saveEmpVacationDetails(Integer empId, List<Map<String, Object>> details) {
165→        // 驗證員工存在
166→        String checkSql = "SELECT COUNT(*) FROM EAP.PM_EMPLOYEE WHERE EMP_ID = :empId";
167→        Query checkQuery = em.createNativeQuery(checkSql);
168→        checkQuery.setParameter("empId", empId);
169→        Number count = (Number) checkQuery.getSingleResult();
170→        if (count.intValue() == 0) {
171→            throw new BusinessException("EMP_NOT_FOUND", 400, "員工不存在：" + empId);
172→        }
173→
174→        List<Map<String, Object>> savedRecords = new ArrayList<>();
175→
176→        for (Map<String, Object> detail : details) {
177→            Object empVacationIdObj = detail.get("empVacationId");
178→            Integer vacationSubId = ((Number) detail.get("vacationSubId")).intValue();
179→            BigDecimal maxHours = toBigDecimal(detail.get("maxHours"));
180→            BigDecimal usedHours = toBigDecimal(detail.get("usedHours"));
181→            if (usedHours == null) usedHours = BigDecimal.ZERO;
182→
183→            // B1: 自動計算 UNUSED_HOURS
184→            BigDecimal unusedHours = maxHours.subtract(usedHours);
185→
186→            String beginDateStr = detail.get("beginDate").toString();
187→            String endDateStr = detail.get("endDate").toString();
188→            LocalDate beginDate = LocalDate.parse(beginDateStr);
189→            LocalDate endDate = LocalDate.parse(endDateStr);
190→
191→            TmEmpVacationEntity entity;
192→
193→            if (empVacationIdObj != null) {
194→                // 修改模式
195→                Integer empVacationId = ((Number) empVacationIdObj).intValue();
196→                entity = TmEmpVacationEntity.findByKey(empVacationId);
197→                if (entity == null) {
198→                    throw new BusinessException("RECORD_NOT_FOUND", 400, "記錄不存在：" + empVacationId);
199→                }
200→                // B5: 不修改 CLEAR 欄位 — 保留原值
201→                entity.vacationSubId = vacationSubId;
202→                entity.maxHours = maxHours;
203→                entity.usedHours = usedHours;
204→                entity.unusedHours = unusedHours;
205→                entity.beginDate = beginDate;
206→                entity.endDate = endDate;
207→            } else {
208→                // 新增模式
209→                entity = new TmEmpVacationEntity();
210→                entity.empId = empId;
211→                entity.vacationSubId = vacationSubId;
212→                entity.maxHours = maxHours;
213→                entity.usedHours = usedHours;
214→                entity.unusedHours = unusedHours;
215→                entity.cashOutHours = BigDecimal.ZERO;
216→                entity.beginDate = beginDate;
217→                entity.endDate = endDate;
218→                entity.clear = false;
219→                entity.persist();
220→            }
221→
222→            Map<String, Object> saved = new HashMap<>();
223→            saved.put("empVacationId", entity.empVacationId);
224→            saved.put("empId", entity.empId);
225→            saved.put("vacationSubId", entity.vacationSubId);
226→            saved.put("maxHours", entity.maxHours);
227→            saved.put("usedHours", entity.usedHours);
228→            saved.put("unusedHours", entity.unusedHours);
229→            saved.put("beginDate", DateFormatUtil.formatDate(entity.beginDate));
230→            saved.put("endDate", DateFormatUtil.formatDate(entity.endDate));
231→            savedRecords.add(saved);
232→        }
233→
234→        em.flush();
235→        return savedRecords;
236→    }
