238→    /**
239→     * 刪除員工假別明細（硬刪除）
240→     * 業務規則 B4：結算列（CLEAR=1）不可刪除
241→     * 業務規則 B6：非結算列硬刪除（DELETE FROM）
242→     */
243→    @Transactional
244→    public void deleteEmpVacation(Integer empVacationId) {
245→        TmEmpVacationEntity entity = TmEmpVacationEntity.findByKey(empVacationId);
246→        if (entity == null) {
247→            throw new BusinessException("RECORD_NOT_FOUND", 400, "記錄不存在：" + empVacationId);
248→        }
249→
250→        // B4: 結算列不可刪除
251→        if (Boolean.TRUE.equals(entity.clear)) {
252→            throw new BusinessException("CLEAR_CANNOT_DELETE", 400, "結算記錄不可刪除");
253→        }
254→
255→        // B6: 硬刪除
256→        entity.delete();
257→        em.flush();
258→    }
